861	ngx_engine_njs_destroy(ngx_engine_t *e, ngx_js_ctx_t *ctx,
862	    ngx_js_loc_conf_t *conf)
863	{
864	    njs_int_t           ret;
865	    ngx_js_event_t     *event;
866	    njs_rbtree_node_t  *node;
867	
868	    if (ctx != NULL) {
869	        ret = njs_vm_call_exit_hook(e->u.njs.vm);
870	        if (ret != NJS_OK) {
871	            ngx_js_log_exception(e->u.njs.vm, ctx->log, "exit hook exception");
872	        }
873	
874	        (void) ngx_njs_execute_pending_jobs(e->u.njs.vm, ctx->log);
875	
876	        node = njs_rbtree_min(&ctx->waiting_events);
877	
878	        while (njs_rbtree_is_there_successor(&ctx->waiting_events, node)) {
879	            event = (ngx_js_event_t *) ((u_char *) node
880	                                        - offsetof(ngx_js_event_t, node));
881	
882	            if (event->destructor != NULL) {
883	                event->destructor(event);
884	            }
885	
886	            node = njs_rbtree_node_successor(&ctx->waiting_events, node);
887	        }
888	
889	        if (ngx_js_unhandled_rejection(ctx)) {
890	            ngx_js_log_exception(e->u.njs.vm, ctx->log, "unhandled rejection");
891	        }
892	    }
893	
894	    njs_vm_destroy(e->u.njs.vm);
895	
896	    /*
897	     * when ctx !=NULL e->pool is vm pool, in such case it is destroyed
898	     * by njs_vm_destroy().
899	     */
900	
901	    if (ctx == NULL) {
902	        njs_mp_destroy(e->pool);
903	    }
